INSERT INTO events (event_type, severity, source, description, source_ip, dest_ip, source_port, dest_port, protocol, username, hostname, process_name, command_line, tags, metadata, raw_json, raw_log, mitre_tactic, mitre_technique, event_timestamp)
VALUES
('boleto_fraud', 'critical', 'Browser Security', 'Boleto malware interception: Banking trojan modified "linha digitavel" (barcode number) in browser during Boleto PDF generation. Bank routing code changed from Itau (341) to mule account bank (077). Visual Boleto appears identical. DOM mutation detected on payment page. Amount: R$3,450.', '192.168.1.42', '200.155.89.42', 443, 443, 'HTTPS', 'financeiro_user01', 'WS-FIN-042', 'chrome.exe', 'chrome.exe --dom-mutation-observer', '["boleto_fraud", "malware_interception", "barcode_modification", "dom_mutation", "bank_routing", "brazil"]'::jsonb, '{"fraud_type": "boleto_malware_interception", "amount_brl": 3450, "original_bank_code": "341", "modified_bank_code": "077", "dom_mutation": true, "visual_identical": true, "monthly_volume": 34500}'::jsonb, '{"event": "boleto_intercept", "amount": 3450, "bank_code_original": "341", "bank_code_modified": "077", "nosso_numero_modified": true}'::jsonb, 'Apr 23 14:30:12 browser-security[5678]: CRITICAL boleto_fraud malware_intercept bank_code=341->077 amount=R$3450 BLOCKED', 'TA0009', 'T1185', NOW() - INTERVAL '30 minutes'),

('boleto_fraud', 'critical', 'Email Security', 'Boleto email swap (Man-in-the-Mailbox): Compromised vendor email account replaced legitimate Boleto PDF with modified version. B2B transaction R$67,000. PDF metadata shows different creation tool (Foxit vs original Adobe). Bank code changed in barcode. Active email thread between procurement teams.', '45.67.89.12', '192.168.10.50', 993, 25, 'SMTP', 'procurement_mgr', 'WS-PROC-010', 'thunderbird.exe', 'email-attach-verify --hash --metadata', '["boleto_fraud", "bec", "man_in_the_mailbox", "pdf_swap", "b2b_fraud", "vendor_compromise", "brazil"]'::jsonb, '{"fraud_type": "boleto_email_swap", "amount_brl": 67000, "attack_type": "Business Email Compromise", "vendor_compromised": true, "pdf_metadata_mismatch": true, "original_tool": "Adobe Acrobat", "modified_tool": "Foxit PhantomPDF", "bank_code_changed": true, "monthly_volume": 5800}'::jsonb, '{"event": "boleto_bec_swap", "amount": 67000, "vendor_email": "compras@vendor-compromised.com.br", "pdf_hash_mismatch": true}'::jsonb, 'Apr 23 11:20:45 email-security[9012]: CRITICAL boleto_fraud bec_swap amount=R$67000 vendor_compromised=true BLOCKED', 'TA0009', 'T1114.002', NOW() - INTERVAL '3 hours'),

('boleto_fraud', 'critical', 'Software Integrity', 'Boleto GRF interception via compromised accounting software: Modified DLL in Contmatic Phoenix accounting system. Batch modification of FGTS/DARF tax payment Boletos across 47 client companies. Total at-risk value: R$418,000. Software update from unofficial mirror.', '192.168.4.5', '103.78.45.12', 443, 443, 'HTTPS', 'contabil_admin', 'WS-CONTAB-001', 'contmatic.exe', 'contmatic.exe --generate-grf --batch', '["boleto_fraud", "grf_interception", "tax_fraud", "accounting_software_compromise", "supply_chain", "fgts", "darf", "brazil"]'::jsonb, '{"fraud_type": "boleto_grf_tax_fraud", "amount_brl": 418000, "compromised_software": "Contmatic Phoenix", "attack_vector": "DLL modification via fake update", "client_companies_affected": 47, "tax_types": ["FGTS", "DARF", "GPS"], "monthly_volume": 12300}'::jsonb, '{"event": "boleto_grf_intercept", "software": "Contmatic Phoenix", "dll_modified": true, "clients_affected": 47, "total_at_risk": 418000}'::jsonb, 'Apr 23 09:15:33 software-integrity[3456]: CRITICAL boleto_fraud grf_intercept software=Contmatic clients=47 amount=R$418000 DETECTED', 'TA0001', 'T1195.002', NOW() - INTERVAL '5 hours'),

('boleto_fraud', 'high', 'Fraud Detection', 'Fake segunda via (duplicate) Boleto: Scammer contacted victim claiming original electricity bill Boleto "expired." Sent replacement via WhatsApp with modified bank routing. Used real CPFL Energia branding and correct account number from Serasa data breach. Pressure tactic: "CPF sera negativado."', '177.42.89.56', '189.100.45.67', 443, 443, 'HTTPS', 'victim_consumer', 'MOBILE-Android-14', 'com.whatsapp', 'whatsapp-deliver-boleto', '["boleto_fraud", "segunda_via", "duplicate_scam", "social_engineering", "serasa_breach", "utility_impersonation", "brazil"]'::jsonb, '{"fraud_type": "segunda_via_boleto", "amount_brl": 890, "impersonating": "CPFL Energia", "delivery": "WhatsApp", "data_source": "Serasa breach", "pressure_tactic": "CPF negativado", "monthly_volume": 78200}'::jsonb, '{"event": "boleto_segunda_via", "amount": 890, "brand_impersonated": "CPFL Energia", "delivery": "WhatsApp"}'::jsonb, 'Apr 23 12:45:22 fraud-detection[7890]: HIGH boleto_fraud segunda_via brand=CPFL amount=R$890 delivery=WhatsApp DETECTED', 'TA0001', 'T1566.001', NOW() - INTERVAL '1 hour 30 minutes'),

('boleto_fraud', 'high', 'Fraud Detection', 'Fake condominium fee Boleto: Mass generation targeting 340 apartments in Alphaville Barueri. Physical mail delivery with authentic-looking headers. Bank code differs from official administradora (BV Financeira). Correct unit numbers from leaked property registry data.', '45.33.22.11', '189.100.45.67', 25, 25, 'SMTP', 'scammer_condo', 'MAIL-SERVER-FAKE', 'boleto-generator', 'boleto-gen --batch --condo=alphaville --units=340', '["boleto_fraud", "condominium_fraud", "mass_generation", "property_data_breach", "physical_mail", "brazil"]'::jsonb, '{"fraud_type": "condominium_boleto_fraud", "amount_brl": 1200, "target": "Alphaville Barueri", "apartments_targeted": 340, "delivery": "physical_mail", "bank_code_mismatch": true, "data_source": "property_registry_leak", "monthly_volume": 45600}'::jsonb, '{"event": "boleto_condo_fraud", "target": "Alphaville Barueri", "units": 340, "amount_per_unit": 1200}'::jsonb, 'Apr 23 08:00:00 fraud-detection[2345]: HIGH boleto_fraud condominium target=Alphaville units=340 amount=R$1200 DETECTED', 'TA0001', 'T1566.001', NOW() - INTERVAL '6 hours');


-- =============================================================================
-- SOCIAL ENGINEERING EVENTS (10 events)
-- =============================================================================

INSERT INTO events (event_type, severity, source, description, source_ip, dest_ip, source_port, dest_port, protocol, username, hostname, process_name, command_line, tags, metadata, raw_json, raw_log, mitre_tactic, mitre_technique, event_timestamp)
VALUES
('social_engineering', 'high', 'Social Media Intel', 'Madonna/Celebrity scam (Golpe da Celebridade): Fake Instagram profile impersonating Anitta (37M followers) DMing fans with contest win. Deepfake video message used. Victim asked to pay R$780 "booking fee" via PIX. 234K monthly attempts nationally. 12% success rate.', '177.80.234.56', '31.13.65.36', 443, 443, 'HTTPS', 'victim_fan_23', 'MOBILE-iOS-17', 'instagram', 'deepfake-detect --video --confidence', '["social_engineering", "celebrity_scam", "madonna_scam", "deepfake", "instagram", "pix", "brazil"]'::jsonb, '{"scam_type": "celebrity_impersonation", "celebrity": "Anitta", "platform": "Instagram", "amount_brl": 780, "deepfake": true, "monthly_attempts": 234000, "success_rate": "12%", "demographic": "age 16-35, female-skewed"}'::jsonb, '{"event": "celebrity_scam", "celebrity": "Anitta", "platform": "Instagram", "amount": 780, "deepfake_confidence": 0.91}'::jsonb, 'Apr 23 13:00:00 social-intel[5678]: HIGH social_engineering celebrity_scam celebrity=Anitta deepfake=true amount=R$780 DETECTED', 'TA0001', 'T1566.003', NOW() - INTERVAL '1 hour 20 minutes'),

('social_engineering', 'critical', 'Web Fraud Detection', 'Fake auction site (Leilao Falso): Pixel-perfect clone of Sodre Santoro judicial auction platform. Facebook ad campaign driving traffic. Fake BMW 320i listing at 60% below market. 89K monthly attempts. Domain registered 3 days ago. CNPJ not in official auction registry.', '45.33.89.100', '177.42.200.23', 443, 443, 'HTTPS', 'victim_bidder', 'WS-HOME-001', 'chrome.exe', 'domain-age-check --whois', '["social_engineering", "fake_auction", "leilao_falso", "judicial_auction", "facebook_ads", "brazil"]'::jsonb, '{"scam_type": "fake_auction", "impersonating": "Sodre Santoro", "platform": "Fake website + Facebook Ads", "amount_brl": 12400, "vehicle": "BMW 320i", "discount_claimed": "60%", "domain_age_days": 3, "monthly_attempts": 89000, "success_rate": "8%"}'::jsonb, '{"event": "fake_auction", "domain": "sodresantoro-leilao-oficial.com.br", "domain_age": 3, "cnpj_valid": false}'::jsonb, 'Apr 23 10:30:00 web-fraud[9012]: CRITICAL social_engineering fake_auction domain_age=3d cnpj=INVALID amount=R$12400 DETECTED', 'TA0001', 'T1566.003', NOW() - INTERVAL '4 hours'),

('social_engineering', 'high', 'Messaging Security', 'WhatsApp job scam (Golpe da Falsa Vaga): Mass messages offering R$300/day for "rating products at home." Fake task platform pays small initial amounts (R$20-50) then requires escalating PIX deposits. 456K monthly attempts. 18% success rate. Average victim loss: R$2,300.', '177.71.45.89', '189.100.45.67', 443, 443, 'HTTPS', 'victim_job_seeker', 'MOBILE-Android-14', 'com.whatsapp', 'whatsapp-spam-detect', '["social_engineering", "job_scam", "falsa_vaga", "whatsapp", "advance_fee", "task_platform", "brazil"]'::jsonb, '{"scam_type": "whatsapp_job_scam", "platform": "WhatsApp + Telegram", "promised_income": "R$300/day", "initial_payout_brl": 20, "deposit_required_brl": 2000, "avg_loss_brl": 2300, "monthly_attempts": 456000, "success_rate": "18%"}'::jsonb, '{"event": "job_scam", "platform": "WhatsApp", "promised": 300, "actual_loss": 2300}'::jsonb, 'Apr 23 11:15:00 messaging-security[3456]: HIGH social_engineering job_scam platform=WhatsApp monthly_attempts=456K DETECTED', 'TA0001', 'T1566.001', NOW() - INTERVAL '3 hours'),

('social_engineering', 'critical', 'Financial Fraud Intel', 'Fake investment platform (Piramide Digital): Telegram group with 52K members showing fake profit screenshots. Ponzi scheme promising 3% daily returns on crypto. Initial R$500 investments return real profits to hook victims. Platform freezing withdrawals after R$12M collected. Average victim: R$8,900.', '95.217.45.67', '177.42.300.45', 443, 443, 'HTTPS', 'victim_investor', 'WS-HOME-002', 'telegram', 'ponzi-pattern-detect', '["social_engineering", "fake_investment", "piramide_digital", "ponzi", "crypto", "telegram", "cvm_unregistered", "brazil"]'::jsonb, '{"scam_type": "fake_investment_platform", "platform": "Telegram + Instagram", "promised_return": "3% daily", "telegram_members": 52000, "total_collected_brl": 12000000, "avg_loss_brl": 8900, "monthly_attempts": 167000, "success_rate": "15%", "cvm_registered": false}'::jsonb, '{"event": "ponzi_scheme", "platform": "Telegram", "members": 52000, "total_stolen": 12000000}'::jsonb, 'Apr 23 09:00:00 financial-intel[7890]: CRITICAL social_engineering ponzi platform=Telegram members=52K stolen=R$12M DETECTED', 'TA0001', 'T1566.003', NOW() - INTERVAL '5 hours'),

('social_engineering', 'medium', 'PIX Fraud Engine', 'Wrong PIX refund scam (Golpe do PIX Errado): Pattern detected - attacker sends R$50 PIX then requests refund to different key. MED claim filed on original. Double collection: net R$100 per victim. 890K monthly attempts. 34% success rate. Highest-volume PIX scam in Brazil.', '177.42.100.23', '189.100.45.67', 443, 443, 'HTTPS', 'scammer_errado', 'MOBILE-Android-13', 'pix-app', 'med-abuse-detect', '["social_engineering", "wrong_pix", "pix_errado", "med_abuse", "high_volume", "brazil"]'::jsonb, '{"scam_type": "wrong_pix_refund", "amount_brl": 50, "net_gain_per_victim": 100, "success_rate": "34%", "monthly_attempts": 890000, "demographic": "all demographics, especially elderly"}'::jsonb, '{"event": "wrong_pix_scam", "initial_send": 50, "refund_key_different": true, "med_abuse": true}'::jsonb, 'Apr 23 13:30:00 pix-fraud[1234]: MEDIUM social_engineering wrong_pix monthly=890K success=34% DETECTED', 'TA0040', 'T1565.003', NOW() - INTERVAL '30 minutes');


-- =============================================================================
-- CPG SUPPLY CHAIN / ICS / COUNTERFEIT EVENTS (15 events)
-- =============================================================================

INSERT INTO events (event_type, severity, source, description, source_ip, dest_ip, source_port, dest_port, protocol, username, hostname, process_name, command_line, tags, metadata, raw_json, raw_log, mitre_tactic, mitre_technique, event_timestamp)
VALUES
('supply_chain_attack', 'critical', 'EDI Monitor', 'CPG supply chain: Compromised EDI 856 ASN feed via 3PL gateway injected falsified Advanced Shipping Notices across 14 distribution centers. SAP S/4HANA MRP auto-generated $23M in duplicate procurement orders. Target: Global Beverage Corp demand planning module.', '10.100.50.42', '10.100.50.1', 1364, 1364, 'AS2', 'edi_gateway_svc', 'EDI-GATEWAY-PROD', 'edi-processor', 'edi856 --process --validate-asn', '["supply_chain", "edi_injection", "sap_s4hana", "mrp_manipulation", "cpg", "beverage", "3pl_compromise"]'::jsonb, '{"attack_type": "edi_asn_injection", "target_system": "SAP S/4HANA", "module": "Demand Planning / MRP", "brand": "Global Beverage Corp", "distribution_centers": 14, "duplicate_orders_usd": 23400000, "vector": "Compromised 3PL EDI gateway", "region": "NA - East Coast"}'::jsonb, '{"event": "edi_asn_injection", "asn_count": 847, "phantom_receipts": 14, "po_value": 23400000}'::jsonb, 'Apr 23 14:22:01 edi-monitor[4891]: CRITICAL supply_chain edi_injection SAP DCs=14 PO_value=$23.4M ACTIVE', 'TA0001', 'T1195.002', NOW() - INTERVAL '4 minutes'),

('supply_chain_attack', 'critical', 'IoT Security', 'CPG cold chain IoT: MQTT broker compromise spoofing temperature sensor telemetry on 847 refrigerated containers. Dairy products report valid temps while exceeding safe thresholds. 12,000 pallets potentially contaminated. Listeria survival risk. FreshLife Dairy EU operations.', '10.200.45.89', '10.200.45.1', 1883, 1883, 'MQTT', 'iot_sensor_svc', 'MQTT-BROKER-EU', 'mosquitto', 'mosquitto_sub -t coldchain/+/temp', '["supply_chain", "cold_chain", "iot_compromise", "mqtt", "temperature_spoofing", "food_safety", "dairy", "listeria", "cpg"]'::jsonb, '{"attack_type": "cold_chain_iot_compromise", "protocol": "MQTT", "containers_affected": 847, "pallets_at_risk": 12000, "brand": "FreshLife Dairy", "contamination_risk": "Listeria", "region": "EU - Western Europe", "loss_estimate_usd": 8700000}'::jsonb, '{"event": "mqtt_temp_spoof", "containers": 847, "pallets": 12000, "temp_reported": 4.2, "temp_actual": 12.8}'::jsonb, 'Apr 23 14:04:33 iot-security[5678]: CRITICAL supply_chain cold_chain_spoof containers=847 pallets=12K contamination=Listeria INVESTIGATING', 'TA0040', 'T1565.002', NOW() - INTERVAL '18 minutes'),

('ics_safety', 'critical', 'ICS Monitor', 'CPG plant safety: CIP (Clean-in-Place) caustic concentration setpoint changed from 2.0% to 0.3% NaOH via compromised HMI. Insufficient sanitation allows Listeria survival in bottling lines. HACCP critical limit breached. Beverage Plant Atlanta. EtherNet/IP protocol.', '10.50.100.42', '10.50.100.1', 44818, 44818, 'EtherNet/IP', 'ics_operator', 'CIP-CONTROLLER-ATL', 'cip-plc', 'cip --setpoint --NaOH=0.3', '["ics_safety", "cip_sabotage", "food_safety", "haccp", "listeria", "setpoint_manipulation", "hmi_compromise", "cpg", "beverage"]'::jsonb, '{"attack_type": "cip_setpoint_manipulation", "facility": "Beverage Plant - Atlanta", "system": "CIP Controller", "protocol": "EtherNet/IP", "original_setpoint": "2.0% NaOH", "modified_setpoint": "0.3% NaOH", "contamination_risk": true, "pathogen": "Listeria", "product_line": "Ready-to-Drink Juice", "haccp_breached": true}'::jsonb, '{"event": "cip_setpoint_change", "NaOH_original": 2.0, "NaOH_modified": 0.3, "haccp_violation": true}'::jsonb, 'Apr 23 14:14:22 ics-monitor[3456]: CRITICAL ics_safety cip_sabotage NaOH=2.0->0.3 HACCP=BREACHED contamination=Listeria CONTAINED', 'TA0040', 'T0836', NOW() - INTERVAL '8 minutes'),

('ics_safety', 'critical', 'ICS Monitor', 'CPG plant safety: HTST pasteurizer hold time reduced from 15s to 3s at 72C via PLC program modification. Flow diversion valve logic altered to pass under-pasteurized product. Public health risk for 230K gallon fluid milk batch. Dairy Processing Wisconsin. S7comm protocol.', '10.50.200.18', '10.50.200.1', 102, 102, 'S7comm', 'plc_engineer', 'HTST-PLC-WI', 'htst-controller', 'plc-program --modify --hold-time=3', '["ics_safety", "pasteurizer_sabotage", "food_safety", "htst", "public_health", "dairy", "plc_modification", "cpg"]'::jsonb, '{"attack_type": "pasteurizer_time_manipulation", "facility": "Dairy Processing - Wisconsin", "system": "HTST Pasteurizer", "protocol": "S7comm", "original_hold_time_sec": 15, "modified_hold_time_sec": 3, "temperature_c": 72, "diversion_valve_bypassed": true, "batch_gallons": 230000, "contamination_risk": true, "product_line": "Fluid Milk"}'::jsonb, '{"event": "htst_sabotage", "hold_time_original": 15, "hold_time_modified": 3, "batch_size": 230000}'::jsonb, 'Apr 23 13:48:11 ics-monitor[7890]: CRITICAL ics_safety pasteurizer_sabotage hold_time=15->3s batch=230K_gal CONTAINED', 'TA0040', 'T0836', NOW() - INTERVAL '34 minutes'),

('ics_safety', 'critical', 'Safety Interlock Monitor', 'CPG plant safety: SIL-2 high-temperature interlock on continuous fryer forced to bypass mode. Oil temperature exceeding flash point (330C). Fire suppression system also disabled via separate attack vector. Dual-vector coordinated attack. Snack Factory Dallas. Modbus TCP.', '10.50.300.7', '10.50.300.1', 502, 502, 'Modbus', 'plc_operator', 'FRYER-PLC-DAL', 'fryer-controller', 'modbus --write-register --bypass-interlock', '["ics_safety", "safety_interlock_bypass", "fire_risk", "dual_vector", "coordinated_attack", "modbus", "snack_factory", "cpg"]'::jsonb, '{"attack_type": "safety_interlock_bypass", "facility": "Snack Factory - Dallas", "system": "Continuous Fryer PLC", "protocol": "Modbus TCP", "interlock_bypassed": "SIL-2 high-temp", "oil_temp_c": 330, "flash_point_exceeded": true, "fire_suppression_disabled": true, "dual_vector": true, "product_line": "Potato Chips"}'::jsonb, '{"event": "interlock_bypass", "oil_temp": 330, "flash_point": 315, "fire_suppression": "disabled"}'::jsonb, 'Apr 23 14:07:45 safety-monitor[2345]: CRITICAL ics_safety interlock_bypass oil_temp=330C flash_point_exceeded fire_supp=DISABLED ACTIVE', 'TA0040', 'T0816', NOW() - INTERVAL '15 minutes'),

('counterfeit_detection', 'critical', 'Anti-Counterfeit Platform', 'Counterfeit infant formula detected: 34,500 units across Amazon Marketplace and Pinduoduo. AI image recognition + chemical assay confirms lead content 47x safe limit. Infant mortality risk. Product seized in Guangzhou. SKU: NF-INF-001-32oz.', '10.0.50.42', '10.0.50.1', 443, 443, 'HTTPS', 'brand_protection', 'ANTI-COUNTERFEIT-SYS', 'ai-image-scan', 'counterfeit-detect --sku=NF-INF-001 --chemical-assay', '["counterfeit", "infant_formula", "lead_contamination", "health_risk", "amazon", "pinduoduo", "china", "cpg", "product_safety"]'::jsonb, '{"fraud_type": "counterfeit_product", "product": "Premium Infant Formula (Stage 1)", "sku": "NF-INF-001-32oz", "quantity": 34500, "platform": "Amazon + Pinduoduo", "origin": "Guangzhou, China", "health_risk": "Lead content 47x safe limit - infant mortality risk", "detection_method": "AI Image Recognition + Chemical Assay", "status": "seized"}'::jsonb, '{"event": "counterfeit_detection", "sku": "NF-INF-001-32oz", "units": 34500, "lead_level": "47x safe limit"}'::jsonb, 'Apr 23 13:00:00 anti-counterfeit[8901]: CRITICAL counterfeit infant_formula units=34500 lead=47x_limit SEIZED', 'TA0040', 'T1565.001', NOW() - INTERVAL '1 hour'),

